from openai import OpenAI
import json
from typing import Callable

def get_weather(location: str, unit: str = "celsius") -> dict:
    """Simulated weather API."""
    return {"location": location, "temperature": 22, "unit": unit, "condition": "sunny"}

def search_web(query: str) -> dict:
    """Simulated web search."""
    return {"query": query, "results": ["Result 1", "Result 2", "Result 3"]}

def calculator(expression: str) -> dict:
    """Safe calculator."""
    try:
        result = eval(expression)
        return {"expression": expression, "result": result}
    except Exception as e:
        return {"error": str(e)}

# Tool registry
tools_registry: dict[str, Callable] = {
    "get_weather": get_weather,
    "search_web": search_web,
    "calculator": calculator
}

# Tool definitions
tool_schemas = [
    {
        "type": "function",
        "function": {
            "name": "get_weather",
            "description": "Get current weather for a location",
            "parameters": {
                "type": "object",
                "properties": {
                    "location": {"type": "string", "description": "City name"},
                    "unit": {"type": "string", "enum": ["celsius", "fahrenheit"]}
                },
                "required": ["location"]
            }
        }
    },
    {
        "type": "function",
        "function": {
            "name": "search_web",
            "description": "Search the internet",
            "parameters": {
                "type": "object",
                "properties": {
                    "query": {"type": "string", "description": "Search query"}
                },
                "required": ["query"]
            }
        }
    },
    {
        "type": "function",
        "function": {
            "name": "calculator",
            "description": "Calculate mathematical expressions",
            "parameters": {
                "type": "object",
                "properties": {
                    "expression": {"type": "string", "description": "Math expression"}
                },
                "required": ["expression"]
            }
        }
    }
]

def run_agent(query: str) -> str:
    """Run agent with function calling."""
    client = OpenAI()
    messages = [{"role": "user", "content": query}]

    for _ in range(5):  # Max 5 iterations
        response = client.chat.completions.create(
            model="gpt-5",
            messages=messages,
            tools=tool_schemas,
            tool_choice="auto"
        )

        msg = response.choices[0].message
        messages.append(msg)

        if not msg.tool_calls:
            return msg.content

        # Execute tool calls
        for tool_call in msg.tool_calls:
            func_name = tool_call.function.name
            args = json.loads(tool_call.function.arguments)

            # Execute and get result
            result = tools_registry[func_name](**args)
            messages.append({
                "role": "tool",
                "tool_call_id": tool_call.id,
                "content": json.dumps(result)
            })

    return "Max iterations reached"

# Example usage
result = run_agent("What's the weather in Paris and what's 2+2?")
print(result)
